import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjPictoChart } from "./OjPictoChart";
export { OjPictoChart };

/**
 * Create an instance of [[OjPictoChart]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojPictoChart(driver, By.id('my-oj-picto-chart'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojPictoChart(driver: DriverLike, by: By): Promise<OjPictoChart> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjPictoChart
  if (!(webEl instanceof OjPictoChart)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-picto-chart>`);
  }
  return webEl;
}

register("oj-picto-chart", OjPictoChart);
